<script setup lang="ts">import{useI18n}from'vue-i18n';import type{MonitorRecord}from'@/types/monitor';defineProps<{record:MonitorRecord}>();const{t}=useI18n()</script><template><dl class="details-list monitor-meta"><div><dt>{{t('monitor.requestId')}}</dt><dd>{{record.requestId}}</dd></div><div><dt>{{t('monitor.model')}}</dt><dd>{{record.model}}</dd></div><div><dt>{{t('monitor.route')}}</dt><dd>{{record.api.toUpperCase()}} {{record.route}}</dd></div><div><dt>{{t('monitor.elapsed')}}</dt><dd>{{record.elapsedMs===null?t('monitor.running'):`${record.elapsedMs} ms`}}</dd></div><div><dt>{{t('monitor.http')}}</dt><dd>{{record.statusCode??t('monitor.unknown')}}</dd></div></dl></template>
